# panelValue - the PanelValue object that changed
# prev - the previous value of the PanelValue object that changed
# Make sure the corresponding toggle is enabled in the Panel Execute DAT.

def onOffToOn(panelValue):
	owner = panelValue.owner
	uv = [owner.panel.u,owner.panel.v]
	if panelValue.name == 'lselect':
		owner.ext.ZoomExt.beginPan(uv)
	elif panelValue.name == 'mselect':
		owner.ext.ZoomExt.beginDolly(uv)
	return

def whileOn(panelValue):
	owner = panelValue.owner
	uv = [owner.panel.u,owner.panel.v]
	if panelValue.name == 'lselect':
		owner.ext.ZoomExt.pan(uv)
	elif panelValue.name == 'mselect':
		owner.ext.ZoomExt.dolly(uv)
	return

def onOnToOff(panelValue):
	return

def whileOff(panelValue):
	return

